<?php require_once __DIR__.'/../config/database.php'; require_once __DIR__.'/../includes/functions.php'; require_login(); $id=(int)($_GET['id']??0); $stmt=$pdo->prepare('SELECT c.*,d.*,r.code rule_code FROM consultations c JOIN diagnosis_results d ON d.consultation_id=c.id LEFT JOIN rules r ON r.id=d.rule_id WHERE c.id=?'); $stmt->execute([$id]); $row=$stmt->fetch(); if(!$row) die('Data tidak ditemukan'); [$color,$defaultRec]=diagnosis_meta($row['diagnosis']); $details=$pdo->prepare('SELECT v.code vcode,s.code scode,s.name FROM consultation_details cd JOIN variables v ON v.id=cd.variable_id JOIN symptoms s ON s.id=cd.symptom_id WHERE cd.consultation_id=?'); $details->execute([$id]); require_once __DIR__.'/../includes/header.php'; ?><div class="container"><div class="card p-4"><h2>Hasil Diagnosa</h2><div class="alert alert-<?=$color==='orange'?'warning':$color?>"><h3 class="mb-0">Potensi <?=e($row['diagnosis'])?></h3></div><p><b>Lokasi:</b> <?=e($row['location'])?></p><h5>Working Memory</h5><?php foreach($details->fetchAll() as $d): ?><span class="wm-code"><?=e($d['vcode'])?>: <?=e($d['scode'])?> - <?=e($d['name'])?></span><?php endforeach; ?><h5 class="mt-3">Rule yang Dipakai</h5><p><?=e($row['rule_code'] ?: 'R-DEFAULT')?> - <?=e($row['explanation'])?></p><h5>Alasan & Rekomendasi</h5><p><?=e($row['recommendation'] ?: $defaultRec)?></p><h5>Rule Aktif</h5><p><?=e(implode(', ',json_decode($row['active_rules'],true)?:[]))?></p><h5>Rule Gagal</h5><p><?=e(implode(', ',json_decode($row['failed_rules'],true)?:[]))?></p><h5>Riwayat Inferensi</h5><div class="timeline"><?php foreach(json_decode($row['inference_trace'],true)?:[] as $t): ?><div><b><?=e($t['rule']['code'])?></b> - <?= $t['matched']?'Fire Rule':'Gagal' ?> → <?=e($t['rule']['diagnosis'])?></div><?php endforeach; ?></div><button class="btn btn-outline-primary mt-3" data-print>Print</button></div></div><?php require_once __DIR__.'/../includes/footer.php'; ?>
